"""
MKT Context Commentary — Deuteronomy chapters 11–13
Run: python3 scripts/zc-context-deuteronomy-11-13-fill.py

Source data used:
- data/interlinear/deuteronomy.json
- data/translation/draft/mediating/deuteronomy.json
- data/commentary/jfb/deuteronomy.json (historical background)

Key decisions in this range:
- "The place YHWH will choose" is treated as a progressive revelation culminating in Jerusalem;
  Josiah's reform (2 Kings 22–23) is the historical implementation of ch. 12's centralization program
- Gerizim and Ebal (11:29) are named; their later Samaritan significance is noted where relevant
- Chapter 13's death penalties are situated in ANE covenant-loyalty context, not read anachronistically
- The Dathan-Abiram reference (11:6) cites Num 16 as background
- "Flowing with milk and honey" is understood as a real geographic description of well-watered pasture,
  not mere rhetorical formula
- Blood prohibition (12:23) grounded in the Noahic and Levitical background, not just Deuteronomic
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUT = {
  "11": {
    "1": "<p>'Love the LORD your God and always keep his requirements' — the opening imperative of chapter 11 is the Shema's counterpart. Deuteronomy uses <em>ʾāhab</em> (love) as the primary covenant-loyalty word: not sentiment but enacted loyalty, the kind that keeps statutes. In ANE suzerainty treaties, 'love' was the standard vocabulary for the vassal's loyal obedience to the suzerain; Deuteronomy personalizes the political idiom into a relational covenant between YHWH and Israel.</p>",
    "2": "<p>'Know today — I am not speaking to your children' — Moses distinguishes the adult generation about to cross the Jordan from their children. The adults have direct experience (<em>yāda</em>: experiential knowledge) of YHWH's 'discipline' (<em>mûsār</em>: correction through historical events). The wilderness generation's knowledge is empirical; the children's will be mediated through teaching. This distinction sets up the pedagogical program of vv. 18-20.</p>",
    "3": "<p>The appeal to the Egyptian signs and deeds is Deuteronomy's standard theological argument: YHWH's track record of power and faithfulness, demonstrated publicly against Pharaoh, is the basis for trust and obedience. Egyptian royal propaganda celebrated Pharaoh's power against his enemies; Deuteronomy inverts the frame — YHWH's power, not Pharaoh's, determined Egypt's fate.</p>",
    "4": "<p>'How he caused the waters of the Red Sea to engulf them' — the Reed Sea drowning of the Egyptian army (Exod 14:26-28) is the decisive proof that YHWH 'has defeated them permanently' (<em>wayĕʾabbēd ʾôtām ʿad hayyôm hazzeh</em>: destroyed them to this day). The permanent defeat formula is the covenant's assurance: what YHWH accomplished at the sea has lasting, not merely momentary, force. Egyptian military power that once enslaved Israel is permanently broken.</p>",
    "5": "<p>'What he did to you in the wilderness until you reached this place' — a summary of the entire wilderness period. The phrase acknowledges that the wilderness was both the site of judgment (the condemned generation died there) and the site of provision (manna, water, preserved clothing: 8:3-4). Both punishment and sustenance are YHWH's acts in the wilderness; the appeal is to the whole complex, not merely to the miraculous provisions.</p>",
    "6": "<p>'What he did to Dathan and Abiram' — the Korah-Dathan-Abiram rebellion (Num 16) is cited as proof of YHWH's power to judge within Israel, not merely against Israel's external enemies. Dathan and Abiram challenged Moses's authority; the earth splitting and swallowing them alive was a spectacular visible judgment that the surviving generation witnessed personally. The mention of 'all their households, tents, and every living creature' reflects the corporate consequences of covenant rebellion in the ANE household-unit model.</p>",
    "7": "<p>'Your own eyes saw every great act' — the appeal to eyewitness knowledge is the strongest possible form of argument in oral-culture accountability. What the audience personally witnessed cannot be dismissed as tradition or legend. The Deuteronomic appeal to 'what your eyes saw' is the foundation for the intergenerational transmission — eyewitnesses teach children who will teach their children (11:19-21).</p>",
    "8": "<p>'Therefore keep every commandment' — the ethical imperative follows directly from the historical recitation: because you have seen YHWH's acts, obedience is the rational response to a demonstrated patron. In ANE treaty logic, the vassal's obligation is proportional to the suzerain's demonstrated faithfulness. 'So that you may be strong enough to cross over' — obedience is presented as the enabling condition for successful conquest, not moral abstraction.</p>",
    "9": "<p>'So that you may live long in the land' — the connection between covenant loyalty and land-tenure is one of Deuteronomy's most consistent themes. The land is held as a gift under covenant conditions, not as an inherent ethnic right. The phrase 'a land flowing with milk and honey' (chalav u-devash) describes rich natural pastureland: wild flowers producing honey for bees, and goats and cattle finding abundant grass — a specific, recognizable geography, not a vague paradise metaphor.</p>",
    "10": "<p>'The land you are entering to possess is not like Egypt' — the contrast between Egypt's irrigated agriculture and Canaan's rain-fed agriculture is theologically significant: in Egypt, humans controlled water supply through labor (irrigation 'by foot' = foot-operated shaduf irrigation channels). In Canaan, water comes from heaven — YHWH's direct provision. Israel's agricultural success in Canaan depends on YHWH in a way that Egypt's did not. The theological import: Israel cannot be self-sufficient; they are dependent on the covenant relationship for the land's productivity.</p>",
    "11": "<p>'A land of hills and valleys that drinks in the rain from heaven' — the Canaanite highland terrain receives the Mediterranean winter rains (November-March) that determine agricultural success. The hill-and-valley topography of Judah and Samaria creates microclimates favorable for grain, olives, and vines — the 'grain, new wine, and olive oil' of v. 14. The rain-dependence makes the blessing-curse structure of 11:13-17 concrete: obedience or disobedience directly affects the rainfall on which all food production depends.</p>",
    "12": "<p>'The eyes of the LORD your God are on it from the beginning of the year to its end' — divine agricultural oversight as covenant intimacy. In contrast to the Baʿal cult, which offered ritual manipulation of the weather deity to produce rain, YHWH's provision of rain is a function of covenant faithfulness, not ritual performance. The image of divine eyes watching the land year-round personalizes YHWH's involvement in the agricultural cycle that Canaanite religion addressed through Baʿal worship.</p>",
    "13": "<p>'If you carefully obey the commandments I am giving you today' — the protasis of the blessing-curse conditional. The condition is specifically love-and-service: 'to love the LORD your God and to serve him with all your heart and with all your soul.' The heart-soul combination (<em>bĕkol-lĕbabkem ûbĕkol-nap̄šĕkem</em>) echoes the Shema's demand (6:5), framing agricultural blessing as a function of the same wholehearted covenant loyalty.</p>",
    "14": "<p>'He will send rain on your land at the right time' — the 'early rain' (<em>yôreh</em>, autumn/October-November, for planting) and 'late rain' (<em>malqôš</em>, spring/March-April, for grain filling). These two seasonal rains determined the success or failure of the entire harvest cycle. Their absence was catastrophic: without the early rain, seeds would not germinate; without the late rain, grain would not fill. Elijah's three-year drought (1 Kings 17-18) was the covenant curse made visible — and its end by rain the covenant restored.</p>",
    "15": "<p>'He will provide grass in your fields for your livestock' — the extension of blessing from arable to pastoral economy. Livestock (sheep, goats, cattle, donkeys) were the measure of wealth and the means of sacrifice in Israelite society. Full grass growth in the fields meant healthy herds that could sustain both food production and the sacrificial cult. The verse addresses the entire agricultural-pastoral economy of a typical Israelite household.</p>",
    "16": "<p>'Be careful that you are not led astray' — the Baʿal temptation is the specific danger. Baʿal worship (from the Canaanite storm-and-fertility deity Baʿal Hadad) offered ritual means of controlling rainfall and agricultural productivity. When the harvest was good, the temptation to credit Baʿal and offer devotion to the local high places was powerful. The Baʿal cycle in the Ugaritic texts (discovered at Ras Shamra, 1929) describes Baʿal as the one who 'gives his voice in the clouds' and 'opens the windows of heaven' — precisely the agricultural provision Deuteronomy assigns to YHWH.</p>",
    "17": "<p>'The LORD's anger will burn against you; he will shut up the sky' — covenantal drought as a specific curse: the sky 'shut up' (<em>ʿāṣar haššāmayim</em>) so no rain falls is the negative of v. 14's blessing. The agricultural consequences are direct: no rain → no crops → expulsion from the land. The Elijah cycle (1 Kings 17-18), the prophets' consistent rain-and-drought theology, and Amos's drought-as-judgment passages (Amos 4:6-7) all operate within this Deuteronomic framework.</p>",
    "18": "<p>'Impress these words of mine on your hearts and minds' — the tefillin/phylactery instruction (cf. 6:8): the <em>tôtāpôt</em> (frontlets/bands) are symbols that later Jewish practice interpreted as leather boxes containing Torah passages worn on the forehead and arm during morning prayer. Whether this was the original intent or whether the instruction was initially metaphorical for internalization is debated. By the Second Temple period, phylacteries were physical objects; their discovery at Qumran (containing Deut 6:4-9 and 11:13-21) confirms the practice well before the NT era.</p>",
    "19": "<p>'Teach them to your children' — the <em>šinnantam</em> (teach diligently, literally 'sharpen them into') instruction for parental religious education. The four contexts — sitting at home, walking on the road, lying down, rising up — cover the entire daily circuit, embedding Torah recitation in every domestic and social transition. This is the Deuteronomic educational program: no separate schooling, but continuous parental transmission throughout the normal day. The Mishnah's recitation of the Shema twice daily formalizes this home-based teaching rhythm.</p>",
    "20": "<p>'Write them on the doorframes of your houses and on your gates' — the <em>mĕzûzāh</em> instruction. Doorframe inscriptions marking sacred boundaries were attested in the ANE (Egyptian household protective inscriptions on doorposts). Deuteronomy sanctifies this protective-inscription practice by replacing protective spells with Torah text. Mezuzah cases containing Deut 6:4-9 and 11:13-20 have been found at Qumran and are in widespread use to this day — among the most durable physical expressions of this verse.</p>",
    "21": "<p>'As long as the heavens are above the earth' — the cosmic durability formula for covenant promises. The comparison to the permanence of the physical cosmos (heavens above earth) was the standard hyperbole for irrevocable commitment in ANE royal inscriptions and treaties. Applied to the land promise, it asserts that the covenant's blessing — long life in the land — is as secure as the created order, conditional only on the obedience specified in vv. 13-20.</p>",
    "22": "<p>'If you carefully observe all this command — to love the LORD your God, to walk in all his ways, and to hold fast to him' — the three-part covenant formula (love-walk-hold fast) is Deuteronomy's summary of the covenant relationship. <em>Dābaq</em> (hold fast, cleave to) is the same verb used for marital bonding (Gen 2:24) and Ruth's loyalty to Naomi (Ruth 1:14) — it denotes the kind of adhesion that survives pressure and separation. Holding fast to YHWH when surrounded by Canaanite alternatives requires the same dogged loyalty.</p>",
    "23": "<p>'Then the LORD will drive out all these nations before you, and you will dispossess nations greater and more powerful than you' — the divine warrior promise: YHWH does the driving out; Israel benefits from and participates in the military campaign. 'Greater and more powerful' acknowledges Israel's military inferiority relative to the entrenched Canaanite city-states with their chariots and fortifications. The promise is explicitly that the dispossession exceeds Israel's natural military capacity — requiring YHWH's supernatural participation.</p>",
    "24": "<p>'Every place where you set your foot will be yours' — the foot-tread formula for land claiming (cf. Josh 1:3: 'Every place that the sole of your foot will tread upon I have given to you'). In ANE custom, walking the land was the formal act of taking possession — the physical movement through territory constituted a claim. The borders named (wilderness to Lebanon, Euphrates to Mediterranean) correspond to the maximal Davidic-Solomonic territorial claim (1 Kings 4:21, 24) — never fully achieved until the united monarchy.</p>",
    "25": "<p>'The LORD your God will cause all the peoples of the land you walk through to fear and dread you' — the holy-war fear formula enacted in advance: divine terror preceding the army (cf. Exod 15:14-16; Josh 2:9-11; Rahab's testimony). Psychological warfare was a recognized element of ANE military strategy; the divine terror that precedes Israel's army is YHWH fighting the psychological dimension of the battle before the physical engagement begins.</p>",
    "26": "<p>'See, I am placing before you today a blessing and a curse' — the formal inauguration of the treaty's sanctions section. ANE suzerainty treaties routinely concluded with lists of blessings (for treaty observance) and curses (for treaty violation), invoked before divine witnesses. Deuteronomy 28 expands these at length; here Moses announces the structure in summary form. The 'today' (<em>hayyôm</em>) of the covenant ceremony is characteristic of Deuteronomic legal speech — the covenant is always contemporaneous, never merely historical.</p>",
    "27": "<p>'The blessing will come if you obey the commandments' — the blessing's condition is comprehensive covenantal loyalty (not specific individual laws). Deuteronomy's blessings are not mechanical rewards for specific acts but outcomes of the relational covenant. The fertility of the land (v. 14-15), success in battle (v. 23-24), and longevity in the land (v. 9, 21) are the primary content of the blessing.</p>",
    "28": "<p>'The curse will come if you do not obey' — the apodosis is specified more narrowly: 'turn from the way I am commanding you today to follow other gods you have not known.' Idolatry is the paradigm curse-trigger in Deuteronomy — the first and second commandments' violation. 'Gods you have not known' is the standard Deuteronomic characterization of foreign deities: not necessarily claimed to be non-existent, but unknown — lacking the relational history with Israel that constitutes covenant identity.</p>",
    "29": "<p>'You are to proclaim the blessing from Mount Gerizim and the curse from Mount Ebal' — the ceremony described in full in Deuteronomy 27 and enacted in Joshua 8:30-35 after the conquest of Ai. Gerizim and Ebal stand opposite each other in the Shechem pass (modern Nablus), creating a natural amphitheater. The six blessing-tribes stand on Gerizim (south, associated with life: Simeon, Levi, Judah, Issachar, Joseph, Benjamin), the six curse-tribes on Ebal (north). Shechem was already the site of Abraham's first covenant altar in Canaan (Gen 12:6-7), linking the blessing-curse ceremony to the patriarchal promise.</p>",
    "30": "<p>'Are these mountains not west of the Jordan, along the road toward the sunset' — Moses's geographical orientation confirms the plains of Moab vantage point: 'west of the Jordan' and 'toward the sunset' describes the direction from Moab looking into Canaan. 'Near Gilgal, beside the great trees of Moreh' — Moreh's trees (Gen 12:6, the oak of Moreh at Shechem) are ancient sacred landmarks. The Canaanite religious associations of Moreh's oaks are being reconsecrated: the place that once hosted pagan sacred trees now hosts Israel's covenant ceremony.</p>",
    "31": "<p>'You are about to cross the Jordan to enter and possess the land' — the transition from promise to possession, from Moses's speech in Moab to the impending Joshua campaign. The crossing of the Jordan is presented as imminent and certain. In ANE royal grant documents, the grant is established by speech-act but becomes effective when the vassal physically takes possession; the Jordan crossing is the moment of activation.</p>",
    "32": "<p>'Be careful to observe all the statutes and ordinances I am setting before you today' — the closing exhortation of the historical-prologue section (chs. 1-11) and the transition marker before the detailed legal code (chs. 12-26) begins. The phrase 'setting before you today' is Deuteronomy's characteristic formula for the living covenant address — not a dead document but a present, immediate claim on the assembly gathered in Moab.</p>",
  },
  "12": {
    "1": "<p>'These are the statutes and ordinances you must carefully observe in the land' — the formal heading for the legal code of chs. 12-26. The phrasing 'in the land' is significant: these laws are not wilderness regulations but land-settlement laws, specific to the conditions of territorial life. The conditional clause 'for as long as you live on the earth' binds land tenure and covenant observance: you hold the land as long as you keep the statutes.</p>",
    "2": "<p>'Completely destroy all the places where the nations served their gods' — the Canaanite worship landscape was densely organized around high places (<em>bāmôt</em>), sacred groves, and standing stones at elevated natural sites throughout the hill country. Archaeology has confirmed the widespread presence of cultic installations on hilltops across Canaan (Megiddo, Hazor, Tel Arad, Tel Dan). The command targets not merely idols but the entire spatial infrastructure of Canaanite worship — the physical landscape that shaped religious behavior.</p>",
    "3": "<p>'Tear down their altars, smash their sacred pillars, burn their Asherah poles, and cut down their carved idols' — the four elements of Canaanite high-place worship: <em>mizbĕḥôt</em> (altars), <em>maṣṣēbôt</em> (standing stones/steles), <em>ʾăšērîm</em> (wooden poles or trees representing the goddess Asherah), and <em>pĕsîlîm</em> (carved idols). The Asherah poles are particularly significant: Asherah was the consort of El in Ugaritic religion, sometimes invoked alongside YHWH in Israelite practice (as attested in the Kuntillet ʿAjrud inscriptions: 'YHWH of Samaria and his Asherah'). The command to burn the names of their gods represents the legal formula for eliminating treaty partners — removing the name removes the legal existence.</p>",
    "4": "<p>'You must not worship the LORD your God in the same way as these nations worship their gods' — the principle underlying the entire code of ch. 12: syncretism is forbidden not because YHWH is one of many gods who can be worshipped in any form, but because YHWH's self-disclosure determines the acceptable form of his worship. The Canaanite cultic practices (high places, Asherah poles, child sacrifice: v. 31) are not simply adopted and redirected to YHWH; the worship form itself must be transformed.</p>",
    "5": "<p>'The place the LORD your God will choose from among all your tribes to establish his name' — the <em>māqôm ʾăšer yibḥar Yhwh</em> (the place YHWH will choose) is the most important phrase in Deuteronomy's cultic program. It is deliberately unnamed — Moses cannot name it because it has not yet been chosen. The progressive revelation culminates in David's selection of Jerusalem (2 Sam 6-7) and Solomon's building of the temple (1 Kings 8). The phrase 'to establish his name' (<em>lĕšakkēn šĕmô šām</em>) uses the theology of the divine Name as a presence-concept: YHWH's name represents his active presence without requiring crude localizing of the divine being.</p>",
    "6": "<p>'There bring your burnt offerings and sacrifices, your tithes and special gifts, your vow offerings and freewill offerings' — the full catalogue of offerings that must go to the central sanctuary. The classification distinguishes: (1) required offerings (<em>ʿōlôt</em>, burnt offerings; <em>zĕbāḥîm</em>, peace offerings); (2) required shares (<em>maʿăśĕrôt</em>, tithes; <em>tĕrûmôt</em>, contributions); (3) voluntary offerings (<em>nĕdārîm</em>, vows; <em>nĕdābôt</em>, freewill). The full spectrum of Israel's worship economy is brought to one place rather than dispersed among local shrines.</p>",
    "7": "<p>'There you shall eat in the presence of the LORD your God and rejoice' — the communal feast dimension of Israelite sacrifice is foreign to modern Western religious categories. Sacrifices were not merely priestly rites; the peace offerings (<em>šĕlāmîm</em>) involved the worshipper sharing the meal with YHWH (the fat and blood consumed on the altar) and with the priestly community. The joy (<em>śĕmaḥtem</em>) commanded at the central sanctuary reflects the covenant meal's celebratory character — a feast hosted by YHWH at his house.</p>",
    "8": "<p>'You are not to act as we act here today, with everyone doing as he sees fit' — a description of the current wilderness situation, not a license for it. Without a fixed sanctuary, each family or tribal unit managed its own worship arrangements. The phrase 'doing as he sees fit' (<em>kol hayyāšār bĕʿênāyw</em>) echoes the negative formula used for the anarchic period of the judges (Judg 17:6; 21:25) — indicating that the decentralized worship of the wilderness was provisional and problematic, not normative.</p>",
    "9": "<p>'Because you have not yet reached the rest and the inheritance' — <em>hammĕnûḥāh</em> (the rest) and <em>hannāḥălāh</em> (the inheritance): two key covenant-settlement concepts. <em>Mĕnûḥāh</em> (rest) is the condition of living securely in the land without threat from enemies — the condition Solomon achieves (1 Kings 5:4) and that becomes a type for eschatological rest (Heb 4:1-11). The rest is not geographical but political: cessation of the warfare and displacement that characterized the wilderness period.</p>",
    "10": "<p>'When you cross the Jordan and settle in the land ... and he gives you rest from all the enemies surrounding you' — the conditions under which centralized worship becomes mandatory: territorial settlement + military security. The wilderness period's decentralized worship was appropriate to the mobile, insecure situation; the central sanctuary is tied to the stable, secured covenant land. The time of David consolidating Jerusalem and defeating surrounding enemies is the historical fulfillment of these conditions.</p>",
    "11": "<p>'Then bring everything I command you to the place the LORD your God will choose as a dwelling for his name' — the centralization becomes obligatory once the conditions of v. 10 are met. 'A dwelling for his name' (<em>lĕšakkēn šĕmô šām</em>) uses the <em>šākan</em> root (to dwell, tabernacle) — the same root behind <em>miškān</em> (Tabernacle) and the NT's Johannine theology (John 1:14: 'the Word tabernacled among us'). The central sanctuary is the fixed form of the portable Tabernacle's theology of divine presence.</p>",
    "12": "<p>'Rejoice before the LORD your God — you, your sons and daughters, your male and female servants, and the Levites in your towns' — the inclusive joy of the covenant feast. The list of participants deliberately includes social subordinates (servants) and the landless religious class (Levites have no tribal inheritance: 10:9; 12:12). The central sanctuary pilgrimage created a periodic community that transcended the normal stratifications of land-based society.</p>",
    "13": "<p>'Be careful not to offer your burnt offerings at just any place you happen to see' — the prohibition against ad hoc local altars. The phrase 'any place you happen to see' (<em>bĕkol-māqôm ʾăšer tirʾeh</em>) is the antithesis of the divinely chosen place (<em>haqqôm ʾăšer yibḥar Yhwh</em>). The visual temptation to worship at any convenient prominent site — the default Canaanite practice — must be resisted in favor of the pilgrim journey to the single legitimate sanctuary.</p>",
    "14": "<p>'Offer them only at the place the LORD will choose in one of your tribal territories' — the physical centrality of the sanctuary in 'one of your tribal territories' locates it within the tribal land system while transcending tribal boundaries. Jerusalem, eventually chosen, sits at the traditional boundary between Judah and Benjamin, accessible to the tribal assemblies from all directions. The prescription of a single place within the tribal system anticipates the geographical reality of the chosen site.</p>",
    "15": "<p>'You may slaughter your animals and eat meat in any of your towns' — the critical distinction between sacrificial slaughter (which must occur at the central sanctuary) and secular slaughter (which may happen locally). Before the centralization law, all slaughter had a sacrificial dimension (Lev 17:3-4 forbids all slaughter outside the sanctuary). Deuteronomy relaxes this to permit non-sacrificial meat in local towns — a pastoral accommodation to the reality that most families live too far from the central sanctuary to bring every animal there. 'Both the ceremonially unclean and the clean may eat it' — the absence of sacrificial context removes the purity requirement that applied to sacred meals.</p>",
    "16": "<p>'But you must never eat the blood' — the blood prohibition is the absolute exception to the local-slaughter permission. The prohibition on blood is older than Deuteronomy (Gen 9:4; Lev 17:14) and applies universally, not merely to Israel. Blood is the <em>nepeš</em> (life-force) that belongs to YHWH — the offering of blood (on the altar or poured out) returns life to its divine source. Pouring it on the ground 'like water' neutralizes it — neither consumed nor offered sacrificially.</p>",
    "17": "<p>'Within your own towns you may not eat the tithe of your grain, new wine, or olive oil, or the firstborn of your herds and flocks' — the distinction between the <em>holy share</em> (tithe, firstborn, vow offerings) and ordinary food. These designated portions belong to YHWH and must be consumed in his presence at the central sanctuary, in the covenant feast context of v. 7. The tithe eaten 'before YHWH' was a sharing of the covenant produce with the divine patron — not merely a tax but a table fellowship.</p>",
    "18": "<p>'Instead, eat them in the presence of the LORD your God at the place the LORD your God will choose — you, your son and daughter, your male and female servant, and the Levite in your town' — the pilgrimage meal reiterates the inclusive community: the whole household (including servants and the local Levite) travels to the central sanctuary for the covenant feast. The 'Levite in your town' clause is repeated (v. 12, 18, 19) with some insistence — the landless Levites depending on local patronage must be included in the pilgrim community's generosity.</p>",
    "19": "<p>'Be careful not to neglect the Levite as long as you live in your land' — the Levites' economic vulnerability is a specific covenantal concern. Without territorial inheritance (they received cities but no agricultural land in the tribal system), Levites depended on tithe shares and charitable inclusion in covenant meals. Their neglect was a structural covenant failure: the tribe entrusted with Torah-teaching and sanctuary service was deliberately left without independent agricultural income, requiring the community's ongoing support as a test of covenant solidarity.</p>",
    "20": "<p>'When the LORD your God extends your territory as he has promised, and you desire to eat meat' — the anticipation of expanded territorial settlement making the central sanctuary increasingly distant for peripheral settlers. The pastoral accommodation of vv. 20-25 addresses the real logistical problem of a geographically large covenant community: enforcing central-sanctuary-only slaughter across a wide territory would create severe practical hardships for families far from Jerusalem.</p>",
    "21": "<p>'If the place where the LORD your God will establish his name is too far away, you may slaughter from your herd or flock' — the 'too far' provision demonstrates Deuteronomy's pastoral realism. Legal idealism (all slaughter must be sacrificial) is modified by geographic reality (most Israelites cannot travel to Jerusalem for every meal). The relaxation maintains the absolute prohibition on blood while allowing daily meat consumption without pilgrimage — a workable division between sacred and secular slaughter.</p>",
    "22": "<p>'Eat it as you would gazelle or deer' — the comparison to game animals is significant: wild game was never under the sacrificial-slaughter requirement (Lev 17:13-14 permits hunting game with only the blood-pouring requirement). Local-slaughter domestic animals are placed in the same category as hunted animals — food rather than sacrificial offerings. The democratization of meat eating that comes with the centralization program (previously all meat was tied to sanctuary access) is a significant social change for Israelite households.</p>",
    "23": "<p>'Do not eat the blood, because the blood is the life-force' — <em>hannep̄eš hûʾ haddām</em>: 'the life is the blood.' The identification of blood as <em>nepeš</em> (life-soul-force) is the theological principle undergirding all blood prohibitions across the Pentateuch. The <em>nepeš</em> belongs to YHWH (Lev 17:11: 'the life of the flesh is in the blood, and I have given it for you on the altar to make atonement for your lives'). Eating blood would be consuming the life that belongs to the Creator — a violation of the fundamental distinction between Creator-owned life and creature-consumed food.</p>",
    "24": "<p>'Do not eat it. Pour it out on the ground like water' — the repetition of the blood prohibition (three times in vv. 16, 23-25) reflects its importance and the anticipated pressure of the concession to local slaughter. Pouring on the ground returns the blood/life to the earth from which it came — a less formal version of the altar-pouring that returns life to YHWH in the sanctuary context. Neither consumed nor treated as sacrificial offering, the ground-pouring is a neutral but reverent disposal.</p>",
    "25": "<p>'Do not eat it, so that it may go well with you and with your children after you' — the blood prohibition's reward formula. The connection between blood-abstinence and intergenerational well-being reflects the covenant's multigenerational scope: YHWH's relationships are not only with living individuals but with lineages. 'Doing what is right in the LORD's sight' — the blood prohibition as a marker of covenantal righteousness, singled out as important enough to warrant three separate prohibitions in this chapter.</p>",
    "26": "<p>'But take your sacred gifts and vow offerings and go to the place the LORD will choose' — the firm line between what can be done locally (secular slaughter, ordinary eating) and what must be done centrally (the sacred portions). The vow offerings (<em>nĕdārîm</em>) represent deliberate sacred commitments made to YHWH — they cannot be discharged locally because they were made to YHWH at his house.</p>",
    "27": "<p>'Present your burnt offerings — both the flesh and the blood — on the altar' — the contrast with secular slaughter: for sacrificial animals, both the flesh (on the altar fire) and the blood (dashed on the altar) are presented to YHWH. For peace offerings (<em>zĕbāḥîm</em>), the blood goes on the altar but the flesh may be eaten by the offerer and priests. The Levitical sacrificial system's careful division of the animal between YHWH, priests, and offerers reflects an elaborate theology of table sharing.</p>",
    "28": "<p>'Be careful to obey all these commands I give you, so that it may always go well with you and your descendants' — the closing covenant-compliance formula. 'Good and right in the sight of the LORD' uses both the ethical standard (<em>ṭôb</em>, good) and the covenant-legal standard (<em>yāšār</em>, right/straight) — the double qualification for the whole person living well before YHWH. The intergenerational promise ('you and your descendants') grounds the centralization command in the covenant's multigenerational scope.</p>",
    "29": "<p>'When the LORD your God has cut off the nations you are going to dispossess' — the post-conquest warning that the real spiritual danger comes after military victory, not before. The settled, successful Israelite is more at risk of religious syncretism than the conquering warrior — economic integration with the remaining Canaanite population (despite the ideal of total dispossession) creates social pressure toward accommodation. The warning is addressed to the prosperous, settled heir, not the military campaigner.</p>",
    "30": "<p>'Do not inquire about their gods and say, &ldquo;How did these nations worship their gods? I will do the same&rdquo;' — the syncretistic reasoning the text forbids: adopting effective-looking religious practices from successful neighbors. The question 'how did these nations worship?' reflects a pragmatic religious attitude — effective worship technology transfers across cultic systems. Deuteronomy forbids the very inquiry: the worship form is not separable from the god being worshipped; adopting Canaanite forms inevitably imports Canaanite theological content.</p>",
    "31": "<p>'They practiced every detestable thing the LORD hates — they even burned their sons and daughters as offerings to their gods' — child sacrifice is the culminating example of Canaanite religious practice that makes syncretism categorically unacceptable. Child sacrifice is attested archaeologically and textually in the Phoenician-Canaanite world: the <em>tophet</em> sites at Carthage (an archaeological cemetery of infant cremations) and the biblical references to Molech sacrifice (Lev 18:21; 20:2-5; 2 Kings 23:10; Jer 32:35) confirm the practice. Deuteronomy's prohibition grounds the rejection of Canaanite worship not in mere cultural difference but in YHWH's moral character: these practices are things he hates.</p>",
    "32": "<p>'Everything that I command you, be careful to do. Do not add to it or subtract from it' — the Torah's self-defining closure formula (cf. 4:2). The prohibition against addition and subtraction defines the Torah as a complete and bounded document, not an open-ended developmental tradition. In ANE treaty practice, the non-alteration clause was standard — vassal kings who modified treaty terms unilaterally were in breach. The formula will reappear at Revelation's conclusion (Rev 22:18-19), bracketing the entire biblical canon with the same protective declaration.</p>",
  },
  "13": {
    "1": "<p>'If a prophet or a dreamer of dreams arises among you' — chapter 13 describes three scenarios of enticement to apostasy: (1) a prophet or dreamer who performs signs (vv. 1-5); (2) a close family member who privately entices (vv. 6-11); (3) a city that collectively apostatizes (vv. 12-18). The three cases escalate in social scope (individual → family → community) and in the severity of response required. The prophet/dreamer scenario addresses the most credible form of threat: a figure with apparent divine endorsement.</p>",
    "2": "<p>'And that sign or wonder actually comes to pass, while he says, &ldquo;Let us go after other gods&rdquo;' — the disturbing scenario: a prophet whose predictions or miracles are confirmed but who directs the people to other gods. In Deuteronomy's theology, predictive success alone does not validate a prophet; the critical test is the content of the message. A functionally successful prophet who redirects Israel away from YHWH is definitively a false prophet regardless of the sign's occurrence. The sign authenticates prophetic capacity, not prophetic message.</p>",
    "3": "<p>'The LORD your God is testing you to find out whether you love the LORD your God with all your heart and with all your soul' — the trial theology: false prophets with apparent signs are part of YHWH's testing of covenant loyalty. The same testing language is used for Abraham (Gen 22:1) and Israel in the wilderness (Exod 16:4; Deut 8:2). The test reveals whether Israel's covenant loyalty is robust enough to withstand credible supernatural challenge — whether love for YHWH is prior to and independent of any sign or wonder.</p>",
    "4": "<p>'You shall follow the LORD your God, fear him, keep his commandments, obey his voice, serve him, and hold fast to him' — the six-part covenant-loyalty formula is the positive response to the false prophet's temptation. Each element describes a different dimension of the covenant relationship: following (alignment of direction), fearing (reverent awe), keeping (observance), obeying (responsive action), serving (cultic and moral practice), holding fast (relational adherence). The comprehensiveness of the formula underlines that covenant loyalty cannot be partial.</p>",
    "5": "<p>'That prophet or dreamer must be put to death, because he has incited rebellion against the LORD your God' — the death penalty for false prophecy that leads to apostasy. The reasoning is juridical: the prophet has committed treason against the divine suzerain by inciting rebellion (<em>dibbēr-sārāh</em>: spoken apostasy/rebellion). In ANE treaty law, anyone who induced the vassal to break covenant with the suzerain was guilty of capital treason. 'Purge the evil from your midst' (<em>ûbiʿartā hārāʿ miqqirbĕkā</em>) is Deuteronomy's standard purging formula — the community bears responsibility for maintaining covenant integrity.</p>",
    "6": "<p>'If your brother — your mother's son — or your son or daughter, or the wife of your embrace, or your closest friend secretly entices you' — the second scenario targets the most intimate social bonds. The specific kinship terms escalate in relational intimacy: full sibling (mother's son), child, spouse (wife of your embrace = the most intimate relationship of the household), and best friend. The phrase 'secretly entices' (<em>yĕsîtĕkā bassēter</em>) describes private, whispered solicitation outside the public covenant assembly — a more insidious threat than the public prophet because it operates in the space of trust.</p>",
    "7": "<p>'Gods of the peoples around you, whether near or far, from one end of the earth to the other' — the geographical scope of the temptation: not merely the local Canaanite cults but any foreign deity from any direction. The comprehensive formulation reflects Israel's position at the crossroads of ANE civilization — Egyptian deities to the south, Mesopotamian to the east, Phoenician to the north, and Philistine to the west. The temptation to supplement YHWH worship with the religious practices of neighboring cultures was a constant reality, not a hypothetical danger.</p>",
    "8": "<p>'You shall not consent to him, nor listen to him. Your eye shall not pity him; you shall not spare him or conceal him' — four prohibitions governing the response to a family member's apostasy-enticement. The explicit 'do not pity' and 'do not spare' override the powerful family-loyalty instincts that honor-shame culture demanded. In a society where family honor required protecting and advocating for kin at all costs, the command to refuse protection to an apostatizing family member was shockingly counter-cultural.</p>",
    "9": "<p>'Rather, you shall certainly put him to death. Your hand shall be the first raised against him, and afterward the hand of all the people' — the first-hand requirement for the one who was enticed is psychologically significant: the person who received the private solicitation must be the first to act against the solicitor. This prevents the accused from claiming that only their enemies convicted them — the victim-turned-accuser's first action establishes both their innocence and their covenant loyalty. The communal stoning afterward distributes responsibility across the covenant community.</p>",
    "10": "<p>'You shall stone him to death, because he tried to turn you away from the LORD your God who brought you out of Egypt, out of the house of slavery' — the execution is justified by invoking the redemption narrative: the attempted apostate-enticement is a rejection of the YHWH who redeemed Israel from Egypt. The exodus is not merely historical background but the covenant's defining event — to lead Israel away from YHWH is to attempt to undo the redemption itself and return Israel to the condition of slavery.</p>",
    "11": "<p>'And all Israel shall hear and be afraid' — the public deterrence function of executing the apostate-enticer. The execution is to be known throughout Israel (<em>kol-yiśrāʾēl yišmĕʿû wĕyîrāʾûn</em>) so that 'no one ever does such an evil thing among you again.' ANE legal codes regularly cited public fear as the purpose of capital punishment — the visible consequence instructs the community. The fear generated is not personal cowardice but the healthy reverence (<em>yārēʾ</em>) that corresponds to YHWH's own moral weight.</p>",
    "12": "<p>'If you hear in one of your cities that someone is saying' — the third scenario scales from individual (prophet: vv. 1-5) and family unit (close relative: vv. 6-11) to an entire city. The report-and-investigation model assumes the covenant community has an information network: rumors of apostasy in a distant city reach the broader community, triggering a formal inquiry. This reflects the ANE administrative reality of a tribal confederation where misconduct in one area affected the whole covenant body.</p>",
    "13": "<p>'Certain worthless men have gone out from among you' — <em>ʾănāšîm bĕnê-bĕliyaʿal</em>: men of Belial/worthlessness. <em>Bĕlîyaʿal</em> (from <em>bĕlî yāʿal</em>: without profit/worth) is the standard Deuteronomic term for covenant rebels (cf. 1 Sam 2:12; 25:17; 2 Kgs 2:12). The personification of Belial as a demonic figure develops in Second Temple literature (Dead Sea Scrolls; 2 Cor 6:15) and is applied by Paul to the category of covenant-breakers. The 'worthless' men who 'go out from among you' — abandoning the covenant community to lead a city into apostasy — are the urban-scale equivalent of the individual apostate-enticer.</p>",
    "14": "<p>'Then you shall investigate thoroughly and inquire carefully' — the requirement of thorough investigation before execution: <em>dārašt wĕḥāqartā wĕšāʾaltā heṭēb</em> (you shall diligently inquire, carefully investigate, and ask thoroughly). Three different investigation verbs reinforce that the judicial process must be exhaustive before any penalty. This procedural requirement prevents mob violence against an innocent city on false reports. The Deuteronomic legal system consistently requires careful evidentiary procedures before capital verdicts (17:4; 19:18).</p>",
    "15": "<p>'You shall certainly strike down the inhabitants of that city with the sword, devoting it to complete destruction' — the <em>ḥērem</em> (ban/devotion to destruction) applied to a whole Israelite city that has apostatized. The application of the same war-ban used against Canaanite cities (Deut 7:2; 20:17) to an Israelite city represents the ultimate internal purging: an apostate Israelite city is equivalent to an enemy Canaanite city and receives the same treatment. The livestock are included — all living things that participated in the apostate city's life are devoted.</p>",
    "16": "<p>'You shall gather all its plunder into the center of its public square and burn the city and all its plunder as a whole offering to the LORD your God' — the apostate city's wealth is burned as a <em>kālîl</em> (whole burnt offering) to YHWH: not distributed as spoil (as in normal conquest) but entirely destroyed. The public square burning requires concentration and visibility — the entire community must witness the <em>ḥērem</em>'s execution, confirming it is complete. 'It shall be a permanent ruin; it must never be rebuilt' — the permanent desolation (<em>tel</em>) as a lasting covenant testimony. Several Canaanite destruction sites excavated by archaeologists preserve this physical 'tell' testimony.</p>",
    "17": "<p>'None of the devoted things shall cling to your hand, so that the LORD may turn from his burning anger' — the warning against the Achan-pattern: taking forbidden devoted items as personal spoil. Achan's violation of the Jericho <em>ḥērem</em> (Josh 7) demonstrates the covenant danger of contaminating the community with devoted goods. The <em>ḥērem</em> works only if completely executed; partial obedience — keeping the best items — is treated as a covenant violation that puts the whole community under YHWH's anger.</p>",
    "18": "<p>'When you obey the voice of the LORD your God by keeping all his commandments' — the chapter closes with the covenant compliance formula, as ch. 12 did (v. 28). The entire legal code of chs. 12-26 is framed by this formula: faithful execution of the covenant's laws (including the harsh measures against apostasy) is the condition for YHWH's compassion and the fulfillment of the patriarchal multiplication promise. The severity of the apostasy laws is not punitive excess but the covenantal cost of maintaining the exclusive loyalty that the Shema demands.</p>",
  },
}

def main():
    existing = load_comm('mkt-context', 'deuteronomy')
    merge_comm(existing, DEUT)
    save_comm('mkt-context', 'deuteronomy', existing)
    il = json.loads((ROOT / 'data/interlinear/deuteronomy.json').read_text())
    out = json.loads((ROOT / 'data/commentary/mkt-context/deuteronomy.json').read_text())
    all_ok = True
    for ch in range(11, 14):
        ck = str(ch)
        missing = [v for v in il.get(ck, {}) if v not in out.get(ck, {})]
        if missing:
            print(f'  ch {ch} MISSING: {missing}')
            all_ok = False
        else:
            print(f'  ch {ch}: OK ({len(il.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present ✓')

if __name__ == '__main__':
    main()
